+  const socketsByRoom = new Map<string, Set<ServerWebSocket<{ roomId: string; clientId: string; role: "host" | "client" }>>>();
+
+  const broadcastRoomSnapshot = (roomId: string) => {
+    const roomSockets = socketsByRoom.get(roomId);
+    if (!roomSockets) {
+      return;
+    }
