  makeMessage,
  type OffdexWorkspaceSnapshot,
  type RuntimeTarget,
} from "@offdex/protocol";

export class DemoWorkspaceController {
  #store = new WorkspaceSnapshotStore();

  getSnapshot() {
    return this.#store.getSnapshot();
  }

