+  }
+
+  getState() {
+    return structuredClone(this.#state);
+  }
+
+  subscribe(listener: (state: BridgeWorkspaceState) => void) {
+    this.#listeners.add(listener);
+    return () => {
+      this.#listeners.delete(listener);
+    };
+  }
