    if (!socket) {
      throw new Error("Codex app-server is not connected.");
    }

    return new Promise<unknown>((resolve, reject) => {
      this.#pending.set(id, { resolve, reject });
      socket.send(JSON.stringify({ id, method, params }));
    });
